import sys
from functools import lru_cache
input = sys.stdin.readline

def solve():
    n = int(input())
    A = list(map(int, input().split()))

    # State: (l, r, last) where last is the last value appended
    # Returns True if current player wins
    @lru_cache(maxsize=None)
    def dp(l, r, last):
        moves = []
        if l <= r:
            if A[l] > last:
                moves.append((l+1, r, A[l]))
            if A[r] > last:
                moves.append((l, r-1, A[r]))
        if not moves:
            return False
        for nl, nr, nlast in moves:
            if not dp(nl, nr, nlast):
                return True
        return False

    if dp(0, n-1, -1):
        print("Alice")
    else:
        print("Bob")

solve()

